    Node *nodes = (Node *)malloc(n * sizeof(Node));
    for (int i = 0; i < n; i++) {
        nodes[i].color = 0;
        nodes[i].parent = i > 0 ? parents[i-1] : -1;
        nodes[i].farthest = -1;
