        Node[] nodes = new Node[n];
        for (int i = 0; i < n; i++) {
            nodes[i] = new Node();
            nodes[i].color = 0;
            nodes[i].parent = i > 0 ? parents[i-1] : -1;
            nodes[i].farthest = -1;
        }
        for (int i = 0; i < m; i++) {
